// Build-time: inline the 3d-force-graph UMD into graph.html and emit a TS
// string module the WebView loads offline. Re-run if graph.html or the
// vendored lib changes:  node scripts/bundle-graph-html.js
const fs = require("fs");
const path = require("path");
const root = path.join(__dirname, "..");
const html = fs.readFileSync(path.join(root, "src/graph3d/graph.html"), "utf8");
const lib = fs.readFileSync(path.join(root, "assets/vendor/3d-force-graph.min.js"), "utf8");
const inlined = html.replace("/*__FORCEGRAPH_LIB__*/", lib.replace(/<\/script>/g, "<\\/script>"));
const out = `// AUTO-GENERATED by scripts/bundle-graph-html.js — do not edit.\nexport const GRAPH_HTML = ${JSON.stringify(inlined)};\n`;
fs.writeFileSync(path.join(root, "src/graph3d/graphHtml.ts"), out);
console.log("wrote src/graph3d/graphHtml.ts", out.length, "bytes");
